// Combine Indeed HTTP results + parsed job-alert emails into one listings array.
const listings = [];

// 1) Indeed/job API results (node may return an array under a key; adapt as needed)
for (const item of $('Search Indeed (HTTP)').all()) {
  const data = item.json;
  const arr = Array.isArray(data) ? data : (data.results || data.jobs || []);
  for (const j of arr) {
    listings.push({
      title: j.title || j.jobtitle || '',
      company: j.company || j.companyName || '',
      location: j.location || j.formattedLocation || '',
      jd_text: j.jd_text || j.snippet || j.description || '',
      url: j.url || j.link || '',
      source: 'indeed'
    });
  }
}

// 2) Job-alert emails — extract subject + first link as a coarse listing
for (const item of $('Read Job-Alert Emails').all()) {
  const m = item.json;
  if (!m || !m.subject) continue;
  const body = (m.textPlain || m.snippet || '').toString();
  const linkMatch = body.match(/https?:\/\/\S+/);
  listings.push({
    title: m.subject,
    company: '',
    location: '',
    jd_text: body.slice(0, 1500),
    url: linkMatch ? linkMatch[0] : '',
    source: 'email-alert'
  });
}

const profile = $('Latest Profile').first().json;
return [{ json: {
  master_skills_json: profile.skills_json || profile.master_skills_json || '',
  desired_city: profile.desired_city || profile.target_city || '',
  desired_roles: profile.desired_roles || profile.target_roles || '',
  job_listings: listings
} }];

const ranked = $json.output?.ranked || [];
if (!ranked.length) return [];
const lines = ranked.map((r, i) => `${i + 1}. ${r.title} @ ${r.company} (fit ${r.fit_score}) — ${r.why}\n${r.url}`);
return [{ json: {
  event_type: 'job_shortlist',
  company: '',
  role: '',
  details: `Top matches:\n${lines.join('\n\n')}`
} }];
